async (params, browser) => {
  // Open brand resources page
  await browser.open(`https://www.canva.com/${params.brand_topic}/`)

  // Wait for page to load
  await browser.waitForSelector('h1, [role=\'heading\'], main', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to load content
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Extract brand resources
  const brand_data = await browser.evaluate(`const titleEl = document.querySelector('h1, [role="heading"]'); const metaDesc = document.querySelector('meta[name="description"]'); const descEl = document.querySelector('main p, section p'); const sections = []; const sectionEls = document.querySelectorAll('section, main > div'); for (let i = 0; i < Math.min(sectionEls.length, 10); i++) { const el = sectionEls[i]; const headingEl = el.querySelector('h2, h3'); const textEl = el.querySelector('p'); if (headingEl) { sections.push({ heading: headingEl.textContent.trim(), text: textEl ? textEl.textContent.trim().substring(0, 300) : '' }); } } const templates = []; const seen = new Set(); const templateEls = document.querySelectorAll('a[href*="/templates/"]'); for (let i = 0; i < templateEls.length && templates.length < 8; i++) { const el = templateEls[i]; const href = el.href || ''; if (!href || seen.has(href)) continue; seen.add(href); const ariaLabel = el.getAttribute('aria-label') || ''; const nameEl = el.querySelector('h3, h4, [aria-label]'); const imgEl = el.querySelector('img'); templates.push({ title: ariaLabel || (nameEl ? (nameEl.getAttribute('aria-label') || nameEl.textContent.trim()) : ''), image: imgEl ? imgEl.getAttribute('src') : '', url: href }); } const featureLinks = document.querySelectorAll('a[href*="/features/"], a[href*="/create/"]'); const tools = []; featureLinks.forEach(function(el) { const t = el.textContent.trim(); if (t && t.length < 80 && !tools.includes(t)) tools.push(t); }); return { brand_topic: params.brand_topic, title: titleEl ? titleEl.textContent.trim() : '', description: metaDesc ? metaDesc.getAttribute('content') : (descEl ? descEl.textContent.trim().substring(0, 500) : ''), sections: sections, templates: templates, tools: tools.slice(0, 10), url: window.location.href }`)

  return brand_data
}
